query:
{
  cloudSqlInstances(
    where: {
      AND: [
        { publicAccessBlocked: { eq: false } }
        {
          ipAddresses_SOME: { type: { eq: "PRIMARY" } }
          networkSettings_SOME: {
            authorizedNetworks_SOME: { cidrValue: { eq: "0.0.0.0/0" } }
          }
        }
        {
          OR: [
            { tlsStatus: { eq: "" } }
            { tlsStatus: { eq: "disabled" } }
            { tlsMinimumVersion_LT: 1.2 }
          ]
        }
      ]
    }
  ) {
    ...AssetFragment
    tlsStatus
    tlsMinimumVersion
  }
}
